diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..08c30c20d0f8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5154,7 +5154,55 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
                           Constant::getNullValue(SRem->getType()));
     }
   }
+  // icmp (sdiv X, C), X
+  // For |C| > 1: x/c < x  <-->  x > 0  (slt predicate)
+  //              x/c <= x <-->  x >= 0 (sle predicate)
+  //              x/c > x  <-->  x < 0  (sgt predicate)
+  //              x/c >= x <-->  x <= 0 (sge predicate)
+  const APInt *DivisorC = nullptr;
+  if (BO0 && BO0->getOpcode() == Instruction::SDiv &&
+      BO0->getOperand(0) == Op1 && match(BO0->getOperand(1), m_APInt(DivisorC)) &&
+      DivisorC->abs().ugt(1)) {
+    switch (Pred) {
+    case ICmpInst::ICMP_SLT:
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1,
+                          Constant::getNullValue(Op1->getType()));
+    case ICmpInst::ICMP_SLE:
+      return new ICmpInst(ICmpInst::ICMP_SGE, Op1,
+                          Constant::getNullValue(Op1->getType()));
+    case ICmpInst::ICMP_SGT:
+      return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                          Constant::getNullValue(Op1->getType()));
+    case ICmpInst::ICMP_SGE:
+      return new ICmpInst(ICmpInst::ICMP_SLE, Op1,
+                          Constant::getNullValue(Op1->getType()));
+    default:
+      break;
+    }
+  }

+  // icmp X, (sdiv X, C)
+  // Swapped version of above
+  if (BO1 && BO1->getOpcode() == Instruction::SDiv &&
+      BO1->getOperand(0) == Op0 && match(BO1->getOperand(1), m_APInt(DivisorC)) &&
+      DivisorC->abs().ugt(1)) {
+    switch (Pred) {
+    case ICmpInst::ICMP_SGT:
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op0,
+                          Constant::getNullValue(Op0->getType()));
+    case ICmpInst::ICMP_SGE:
+      return new ICmpInst(ICmpInst::ICMP_SGE, Op0,
+                          Constant::getNullValue(Op0->getType()));
+    case ICmpInst::ICMP_SLT:
+      return new ICmpInst(ICmpInst::ICMP_SLT, Op0,
+                          Constant::getNullValue(Op0->getType()));
+    case ICmpInst::ICMP_SLE:
+      return new ICmpInst(ICmpInst::ICMP_SLE, Op0,
+                          Constant::getNullValue(Op0->getType()));
+    default:
+      break;
+    }
+  }
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

